/**
 * PACE Platform — インメモリキャッシュ型定義
 *
 * API ルートのホットデータキャッシュに使用する型。
 */

// ---------------------------------------------------------------------------
// キャッシュエントリ
// ---------------------------------------------------------------------------

export interface CacheEntry<T> {
  data: T;
  expiresAt: number;
  key: string;
}

// ---------------------------------------------------------------------------
// キャッシュ設定
// ---------------------------------------------------------------------------

export interface CacheConfig {
  /** デフォルト TTL（秒） */
  defaultTTL: number;
  /** 最大エントリ数（LRU 超過時に古いエントリを削除） */
  maxEntries: number;
}
